245	/// `debug.getinfo([thread,] f|level [, what])` — collect debug information
246	/// about function `f` or stack level `level` into a new table. The `what`
247	/// string selects which fields to populate (default `"flnSrtu"`).
248	///
249	/// C: `static int db_getinfo(lua_State *L)`
250	pub(crate) fn get_info(state: &mut LuaState) -> Result<usize, LuaError> {
251	    let mut ar = DebugInfo::default();
252	
253	    // C: int arg; lua_State *L1 = getthread(L, &arg);
254	    let (arg, other_thread) = getthread(state);
255	    let target_is_self = other_thread.is_none();
256	
257	    // C: const char *options = luaL_optstring(L, arg+2, "flnSrtu");
258	    // to_vec() immediately to avoid borrow-checker conflict with subsequent &mut state ops.
259	    let raw_opts: Vec<u8> = state.opt_arg_string(arg + 2, b"flnSrtu")?.to_vec();
260	
261	    // C: checkstack(L, L1, 3);
262	    check_cross_thread_stack(state, target_is_self, 3)?;
263	
264	    // C: luaL_argcheck(L, options[0] != '>', arg + 2, "invalid option '>'");
265	    if raw_opts.first() == Some(&b'>') {
266	        return Err(LuaError::arg_error(arg + 2, "invalid option '>'"));
267	    }
268	
269	    // Build the effective options string, prepending '>' when the subject is a function.
270	    let options: Vec<u8>;
271	
272	    if state.type_at(arg + 1) == LuaType::Function {
273	        // C: options = lua_pushfstring(L, ">%s", options);  /* add '>' to options */
274	        // In C this also pushes the string onto the stack; in Rust we just build a Vec.
275	        let mut prefixed = Vec::with_capacity(raw_opts.len() + 1);
276	        prefixed.push(b'>');
277	        prefixed.extend_from_slice(&raw_opts);
278	        options = prefixed;
279	
280	        // C: lua_pushvalue(L, arg + 1);  /* move function to L1 stack */
281	        // C: lua_xmove(L, L1, 1);
